        guard let privateKey = privateKey else { return nil }
        var error: Unmanaged<CFError>?
        guard let signature = SecKeyCreateSignature(privateKey, .ecdsaSignatureMessageX962SHA256, data as CFData, &error) else {
            return nil
        }
        return signature as Data
    }
    
    func sendTransaction(to address: String, amount: Double, completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "https://api.blockchain.com/v3/exchange/transactions") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
